// Find the first PENDING row (FIFO order)
const rows = $input.all();

let pending = null;
let rowIndex = -1;

for (let i = 0; i < rows.length; i++) {
  const s = (rows[i].json.Status || '').toString().trim().toUpperCase();
  if (s === 'PENDING') {
    pending = rows[i].json;
    rowIndex = i + 2; // +1 for 0-index, +1 for header row
    break;
  }
}

if (!pending) {
  throw new Error('QUEUE_EMPTY: No PENDING URLs. Add more via Workflow 1 webhook.');
}

return [{
  json: {
    row_number: rowIndex,
    pinterest_url: (pending.Pinterest_URL || '').trim(),
    status: 'PENDING'
  }
}];

// ──────────────────────────────────────────────────────────────────────────
// Extract Pinterest image using 4 strategies — no API key needed
// ──────────────────────────────────────────────────────────────────────────
const pinterestUrl = $input.first().json.pinterest_url;

const headers = {
  'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/122.0.0.0 Safari/537.36',
  'Accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,image/avif,image/webp,*/*;q=0.8',
  'Accept-Language': 'en-US,en;q=0.9',
  'Cache-Control': 'no-cache',
  'Pragma': 'no-cache'
};

let html = '';
try {
  const res = await $httpRequest({
    method: 'GET',
    url: pinterestUrl,
    headers,
    followRedirects: true,
    timeout: 20000,
    returnFullResponse: true
  });
  html = res.body || '';
} catch(e) {
  throw new Error(`Pinterest fetch failed: ${e.message}`);
}

if (html.length < 200) {
  throw new Error('Pinterest returned empty page — possible bot block. Try a direct /pin/ URL.');
}

let imageUrl = null;

// Strategy 1: og:image
const og = html.match(/<meta[^>]+property=["']og:image["'][^>]+content=["']([^"']+)["']/i)
           || html.match(/<meta[^>]+content=["']([^"']+)["'][^>]+property=["']og:image["']/i);
if (og?.[1]) imageUrl = og[1].replace(/&amp;/g, '&');

// Strategy 2: JSON-LD
if (!imageUrl) {
  const blocks = html.match(/<script[^>]+type=["']application\/ld\+json["'][^>]*>([\s\S]*?)<\/script>/gi) || [];
  for (const b of blocks) {
    try {
      const inner = b.match(/>([\s\S]*?)<\/script>/i)?.[1];
      if (inner) {
        const data = JSON.parse(inner);
        if (data.image) { imageUrl = Array.isArray(data.image) ? data.image[0] : data.image; break; }
      }
    } catch(e) {}
  }
}

// Strategy 3: pinimg CDN regex
if (!imageUrl) {
  const m = html.match(/https:\/\/i\.pinimg\.com\/originals\/[a-f0-9/]+\.(jpg|jpeg|png|webp)/i)
          || html.match(/https:\/\/i\.pinimg\.com\/[^"'\s]+\.(jpg|jpeg|png|webp)/i);
  if (m) imageUrl = m[0];
}

// Strategy 4: embedded app state JSON
if (!imageUrl) {
  const stateMatch = html.match(/window\.__INITIAL_STATE__\s*=\s*(\{[\s\S]+?\});/i)
                  || html.match(/__PWS_DATA__\s*=\s*(\{[\s\S]+?\});/i);
  if (stateMatch) {
    try {
      const raw = JSON.stringify(JSON.parse(stateMatch[1]));
      const m2 = raw.match(/https:\\/\\/i\.pinimg\.com\\/originals\\/[a-f0-9\\/]+\.(jpg|jpeg|png|webp)/i);
      if (m2) imageUrl = m2[0].replace(/\\\/g, '/');
    } catch(e) {}
  }
}

if (!imageUrl) throw new Error(`No image found in: ${pinterestUrl}`);

// Force highest resolution
imageUrl = imageUrl.replace(/\/[0-9]+x[0-9]?\//, '/originals/');

return [{
  json: {
    ...$input.first().json,
    image_url: imageUrl
  }
}];

const caption = `🔥 Men's Fashion Inspiration

Upgrade your wardrobe with timeless style and confidence.

💬 Comment "LINK" for product links
📌 Save this look for later
👔 Follow @styleformenindia for daily men's fashion inspiration

#mensfashion #mensstyle #outfitideas #fashion #style #menswear #streetwear #casualstyle #outfitinspiration #styleformen #fashionreels #indianmensfashion #dailyoutfit #styleinspo #fashiontips`;

return [{
  json: {
    ...$input.first().json,
    caption
  }
}];

const res = $input.first().json;
if (!res.id) throw new Error(`Container failed: ${JSON.stringify(res.error || res)}`);

// Instagram requires a short delay before publishing
await new Promise(r => setTimeout(r, 8000));

return [{
  json: {
    ...$('Code: Build Caption').first().json,
    container_id: res.id
  }
}];

const pub = $input.first().json;
if (!pub.id) throw new Error(`Publish failed: ${JSON.stringify(pub.error || pub)}`);

const prev = $('Code: Validate & Wait 8s').first().json;
const postedDate = new Date().toISOString().replace('T',' ').slice(0,19);

return [{
  json: {
    row_number:       prev.row_number,
    pinterest_url:    prev.pinterest_url,
    instagram_post_id: pub.id,
    posted_date:      postedDate
  }
}];

const e = $input.first().json;
const node = e.execution?.lastNodeExecuted || 'Unknown';
const msg  = e.execution?.error?.message || e.error?.message || 'Unknown error';
return [{ json: { failed_node: node, error_message: msg, time: new Date().toISOString() } }];
